export function findAllSuggestions(query) {
    return query
        .findAllTestCaseFinished()
        .map((testCaseFinished) => query.findPickleBy(testCaseFinished))
        .filter((pickle) => !!pickle)
        .flatMap((pickle) => query.findSuggestionsBy(pickle));
}
